mapper.select:
    /* Baim05Mapper.selectDailyUserSlotList */
	SELECT 
		'' 																AS chk
		, A.CMPNY_CD													AS cmpnyCd
		, A.SITE_CD														AS siteCd
	    , FNC_CMM_INFO_SRCH(A.CMPNY_CD, 'SITE', A.SITE_CD, NULL)		AS siteNm
	    , A.SLOT_NO														AS slotNo
	    , A.SLOT_TYPE													AS slotType
	    , A.FIXED_YN													AS fixedYn
	    , A.USE_YN														AS useYn
	    , A.CURR_USER_ID												AS currUserId
	    , FNC_CMM_INFO_SRCH(A.CMPNY_CD, 'USER', A.CURR_USER_ID, NULL) 	AS currUserNm
	    , A.SLOT_STATUS													AS slotStatus
	FROM TB_DAILY_USER_SLOT A
	WHERE A.CMPNY_CD = #{token.gv_cmpnyCd}

	  	AND A.SITE_CD = #{param.siteCd}


	  	AND A.SLOT_TYPE = #{param.slotType}


	  	AND A.SLOT_STATUS = #{param.slotStatus}


	  	AND A.USE_YN = #{param.useYn}


	  	AND A.USE_YN = #{param.currUserId}

	ORDER BY SITE_CD, CAST(A.SLOT_NO AS UNSIGNED)
